{
  "version": "1.0",
  "projectName": "KiiPS",
  "description": "Korea Investment Information Processing System - Enterprise Microservices Platform",

  "permissions": {
    "allowedTools": [
      "Read",
      "Write(src/**)",
      "Write(KiiPS-*/**/*.java)",
      "Write(KiiPS-*/**/*.jsp)",
      "Write(KiiPS-*/**/*.js)",
      "Edit",
      "Bash(mvn *)",
      "Bash(cd *)",
      "Bash(./start.sh)",
      "Bash(./stop.sh)",
      "Bash(tail *)",
      "Bash(grep *)",
      "Bash(curl *)",
      "Bash(lsof *)",
      "Bash(jq *)",
      "Bash(git *)"
    ],
    "deny": [
      "Write(.env*)",
      "Write(app-kiips.properties)",
      "Bash(rm -rf *)",
      "Bash(sudo *)",
      "Bash(DROP *)",
      "Bash(DELETE FROM *)"
    ]
  },

  "hooks": {
    "SessionStart": [
      {
        "type": "command",
        "command": "bash .claude/hooks/update-reminder.sh"
      }
    ],

    "UserPromptSubmit": [
      {
        "type": "prompt",
        "prompt": "⚠️ KiiPS Build Reminder: Always build from KiiPS-HUB directory with '-am' flag. Never build directly in service directories."
      }
    ],

    "PreToolUse": [
      {
        "matcher": "Bash(mvn *)",
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Are you in KiiPS-HUB directory? Maven builds must start from KiiPS-HUB."
          }
        ]
      }
    ],

    "PostToolUse": [
      {
        "matcher": "Write(**/pom.xml)",
        "hooks": [
          {
            "type": "command",
            "command": "echo '⚠️  pom.xml changed - Rebuild required from KiiPS-HUB'"
          }
        ]
      },
      {
        "matcher": "Bash(./start.sh)",
        "hooks": [
          {
            "type": "command",
            "command": "echo '✅ Service starting... Waiting 5 seconds for health check...'"
          },
          {
            "type": "command",
            "command": "sleep 5 && echo 'Checking health...'"
          }
        ]
      },
      {
        "matcher": "Bash(mvn clean package*)",
        "hooks": [
          {
            "type": "command",
            "command": "echo '✅ Build completed. Check target/ directory for artifacts.'"
          }
        ]
      }
    ],

    "Stop": [
      {
        "type": "command",
        "command": "echo '📝 Session ending. Remember to commit any changes and update dev docs if needed.'"
      }
    ]
  },

  "skillActivation": {
    "rulesFile": "skill-rules.json",
    "autoActivate": true,
    "priority": ["critical", "high", "normal"],
    "enforcement": {
      "require": "block-until-acknowledged",
      "suggest": "show-notification",
      "block": "prevent-action"
    }
  },

  "devDocs": {
    "enabled": true,
    "location": "dev/active/",
    "templates": {
      "plan": "dev/templates/plan-template.md",
      "context": "dev/templates/context-template.md",
      "tasks": "dev/templates/tasks-template.md"
    }
  },

  "environment": {
    "local": {
      "apiGatewayPort": 8000,
      "defaultProfile": "local"
    },
    "staging": {
      "apiGatewayPort": 8000,
      "defaultProfile": "stg"
    },
    "production": {
      "apiGatewayPort": 8000,
      "defaultProfile": "kiips"
    }
  },

  "metadata": {
    "created": "2025-12-28",
    "lastUpdated": "2025-12-28",
    "version": "2.0",
    "maintainer": "KiiPS Development Team"
  }
}

