{
  "kiips-backend-guidelines": {
    "type": "domain",
    "enforcement": "suggest",
    "priority": "high",
    "promptTriggers": {
      "keywords": ["controller", "service", "dao", "API", "endpoint", "REST", "백엔드", "컨트롤러"],
      "intentPatterns": [
        "(create|add|make).*?(controller|service|endpoint)",
        "(fix|debug).*?(API|service)",
        "(how to|best practice).*?(backend|controller)"
      ]
    },
    "fileTriggers": {
      "pathPatterns": ["**/controll/**/*.java", "**/service/**/*.java", "**/dao/**/*.java"],
      "contentPatterns": ["@RestController", "@Service", "extends DAO"]
    }
  },

  "kiips-frontend-guidelines": {
    "type": "domain",
    "enforcement": "suggest",
    "priority": "high",
    "promptTriggers": {
      "keywords": ["JSP", "JavaScript", "UI", "프론트엔드", "화면", "페이지", "jQuery"],
      "intentPatterns": [
        "(create|update|modify).*?(page|screen|UI|화면)",
        "(fix|style).*?(JSP|JavaScript)"
      ]
    },
    "fileTriggers": {
      "pathPatterns": ["**/jsp/**/*.jsp", "**/static/**/*.js", "**/static/**/*.css"],
      "contentPatterns": ["<%@", "$(document)", "function "]
    }
  },

  "kiips-security-check": {
    "type": "guardrail",
    "enforcement": "require",
    "priority": "critical",
    "promptTriggers": {
      "keywords": ["인증", "로그인", "JWT", "토큰", "비밀번호", "암호화", "보안"],
      "intentPatterns": [
        ".*?(auth|login|token).*?",
        ".*?(password|secret|encrypt).*?"
      ]
    }
  },

  "kiips-database-verification": {
    "type": "guardrail",
    "enforcement": "block",
    "priority": "critical",
    "promptTriggers": {
      "keywords": ["database", "DB", "테이블", "스키마", "마이그레이션", "MyBatis"],
      "intentPatterns": [
        ".*?(alter|modify|change).*?table",
        ".*?(drop|delete|truncate).*?",
        ".*?(schema|migration).*?"
      ]
    }
  },

  "kiips-common-patterns": {
    "type": "domain",
    "enforcement": "suggest",
    "priority": "normal",
    "promptTriggers": {
      "keywords": ["COMMON", "UTILS", "GlobalExceptionHandler", "ErrorNotificationService", "공통"],
      "intentPatterns": [
        "(use|implement).*?(common|shared|util)"
      ]
    },
    "fileTriggers": {
      "pathPatterns": ["**/KiiPS-COMMON/**/*.java", "**/KiiPS-UTILS/**/*.java"]
    }
  },

  "kiips-build-deploy": {
    "type": "domain",
    "enforcement": "suggest",
    "priority": "high",
    "promptTriggers": {
      "keywords": ["빌드", "배포", "build", "deploy", "maven", "mvn", "start.sh", "stop.sh"],
      "intentPatterns": [
        "(build|deploy|run).*?(service|module)",
        "(how to).*?(build|deploy)"
      ]
    }
  },

  "kiips-maven-builder": {
    "type": "domain",
    "enforcement": "require",
    "priority": "critical",
    "promptTriggers": {
      "keywords": ["빌드", "build", "maven", "mvn", "compile", "package", "KiiPS-HUB"],
      "intentPatterns": [
        "(build|compile|package).*?(service|module|project)",
        ".*?KiiPS-(FD|IL|PG|COMMON|UTILS).*?(build|빌드)",
        "(how to|need to).*?build"
      ]
    },
    "fileTriggers": {
      "pathPatterns": ["**/pom.xml"],
      "contentPatterns": ["<artifactId>KiiPS-", "<packaging>"]
    }
  },

  "kiips-service-deployer": {
    "type": "domain",
    "enforcement": "require",
    "priority": "high",
    "promptTriggers": {
      "keywords": ["배포", "deploy", "start", "stop", "restart", "서비스 시작", "서비스 중지"],
      "intentPatterns": [
        "(start|stop|restart|deploy).*?service",
        ".*?(배포|시작|중지|재시작).*?서비스",
        "check.*?(health|status)"
      ]
    },
    "fileTriggers": {
      "pathPatterns": ["**/start.sh", "**/stop.sh"]
    }
  },

  "kiips-api-tester": {
    "type": "domain",
    "enforcement": "suggest",
    "priority": "high",
    "promptTriggers": {
      "keywords": ["API", "테스트", "test", "curl", "gateway", "endpoint", "JWT"],
      "intentPatterns": [
        "test.*?(API|endpoint|gateway)",
        "(verify|check).*?(routing|authentication)",
        ".*?(테스트|검증).*?(API|게이트웨이)"
      ]
    }
  },

  "kiips-log-analyzer": {
    "type": "domain",
    "enforcement": "suggest",
    "priority": "high",
    "promptTriggers": {
      "keywords": ["로그", "log", "error", "에러", "exception", "분석", "analyze", "grep"],
      "intentPatterns": [
        "(check|analyze|find).*?(log|error)",
        ".*?(로그|에러).*?(확인|분석|검색)",
        "(troubleshoot|debug).*?issue"
      ]
    },
    "fileTriggers": {
      "pathPatterns": ["**/logs/*.log"]
    }
  }
}
